SET NAMES utf8mb4;
SET time_zone = '+00:00';
CREATE TABLE IF NOT EXISTS feature_flags (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,flag_key VARCHAR(120) NOT NULL UNIQUE,enabled TINYINT(1) NOT NULL DEFAULT 1,config_json LONGTEXT NULL,updated_by BIGINT UNSIGNED NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS platform_events (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NULL,event_name VARCHAR(120) NOT NULL,details_json LONGTEXT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,KEY idx_event_name(event_name),KEY idx_event_user(user_id),KEY idx_event_created(created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS creator_tasks (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,title VARCHAR(180) NOT NULL,description TEXT NOT NULL,category VARCHAR(100) NOT NULL,reward_type ENUM('bits','cash') NOT NULL,reward_bits BIGINT NOT NULL DEFAULT 0,reward_cash DECIMAL(12,2) NOT NULL DEFAULT 0.00,currency CHAR(3) NOT NULL DEFAULT 'USD',status ENUM('draft','open','paused','closed') NOT NULL DEFAULT 'draft',due_at DATETIME NULL,created_by BIGINT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_task_status(status),KEY idx_task_category(category)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS task_submissions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,task_id BIGINT UNSIGNED NOT NULL,user_id BIGINT UNSIGNED NOT NULL,submission_url VARCHAR(500) NOT NULL,notes TEXT NULL,status ENUM('submitted','under_review','changes_requested','approved','rejected','paid') NOT NULL DEFAULT 'submitted',approved_by BIGINT UNSIGNED NULL,approved_at DATETIME NULL,payment_transaction_id BIGINT UNSIGNED NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_submission_task(task_id),KEY idx_submission_user(user_id),KEY idx_submission_status(status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS resume_submissions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NOT NULL,file_path VARCHAR(500) NOT NULL,target_role VARCHAR(180) NOT NULL,status ENUM('received','reviewing','shortlisted','archived') NOT NULL DEFAULT 'received',admin_notes TEXT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_resume_user(user_id),KEY idx_resume_status(status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS user_app_progress (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NOT NULL,app_slug VARCHAR(100) NOT NULL,content_type VARCHAR(80) NOT NULL,content_id VARCHAR(120) NOT NULL,progress_percent DECIMAL(5,2) NOT NULL DEFAULT 0,completed_at DATETIME NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uq_user_progress(user_id,app_slug,content_type,content_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS app_content (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,app_slug VARCHAR(100) NOT NULL,content_type VARCHAR(80) NOT NULL,title VARCHAR(200) NOT NULL,slug VARCHAR(220) NOT NULL,summary TEXT NULL,body LONGTEXT NULL,locale VARCHAR(12) NOT NULL DEFAULT 'en',access_level ENUM('free','premium','admin') NOT NULL DEFAULT 'free',status ENUM('draft','scheduled','published','archived') NOT NULL DEFAULT 'draft',published_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uq_app_content(app_slug,slug,locale),KEY idx_app_content_status(app_slug,status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS translation_keys (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,namespace VARCHAR(100) NOT NULL,key_name VARCHAR(190) NOT NULL,locale VARCHAR(12) NOT NULL,text_value TEXT NOT NULL,status ENUM('draft','reviewed','published') NOT NULL DEFAULT 'draft',updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uq_translation(namespace,key_name,locale)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
INSERT IGNORE INTO feature_flags(flag_key,enabled) VALUES ('beyond_preschool',1),('beyond_careers',1),('creator_tasks',1),('beyond_sell',1),('beyond_finance',1),('admin_command_center',1),('pwa_install_prompt',1);
